// Builds the markdown body for the visual regression PR comment.
// Reads:
//   - current-screenshots/*.png  (always-produced "current" screenshots)
//   - test-results/**/*.png      (Playwright diff/actual/expected on failure)
// Env:
//   PR_NUM, RUN_ID, GITHUB_REPOSITORY, TEST_STATUS ("success" | "failure")
// Output:
//   Writes comment.md, also prints to stdout.

const fs = require("fs");
const path = require("path");

const PR = process.env.PR_NUM;
const RUN = process.env.RUN_ID;
const REPO = process.env.GITHUB_REPOSITORY;
const STATUS = process.env.TEST_STATUS;
const BRANCH = "visual-results";
const BASE =
  `https://raw.githubusercontent.com/${REPO}/${BRANCH}/pr-${PR}/run-${RUN}`;

const passed = STATUS === "success";
const header = passed ? "✅ No visual diff" : "❌ Visual diff detected";

let md = `## Visual Regression: ${header}\n\n`;
md += `Run: [#${RUN}](https://github.com/${REPO}/actions/runs/${RUN})\n\n`;

const currentDir = "current-screenshots";
const currents = fs.existsSync(currentDir)
  ? fs.readdirSync(currentDir).filter((f) => f.endsWith(".png")).sort()
  : [];

if (currents.length > 0) {
  md += `<details${passed ? "" : " open"}>\n`;
  md +=
    `<summary><strong>Current screenshots (${currents.length})</strong></summary>\n\n`;
  for (const f of currents) {
    md += `**${f}**\n\n`;
    md += `<img src="${BASE}/current/${f}" alt="${f}" width="480">\n\n`;
  }
  md += `</details>\n\n`;
}

if (!passed) {
  const diffs = [];
  walk("test-results");

  function walk(dir) {
    if (!fs.existsSync(dir)) return;
    for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
      const p = path.join(dir, entry.name);
      if (entry.isDirectory()) walk(p);
      else if (entry.isFile() && entry.name.endsWith(".png")) diffs.push(p);
    }
  }

  const byTest = {};
  for (const p of diffs) {
    const rel = path.relative("test-results", p);
    const parts = rel.split(path.sep);
    const testDir = parts.slice(0, -1).join("/") || "(root)";
    const file = parts[parts.length - 1];
    const flat = rel.replace(/\//g, "__");
    (byTest[testDir] = byTest[testDir] || []).push({ file, flat });
  }

  md += `### Failed tests\n\n`;
  const testNames = Object.keys(byTest).sort();
  if (testNames.length === 0) {
    md += `_No diff images were produced; see the workflow logs._\n\n`;
  }
  for (const t of testNames) {
    md += `<details open>\n<summary><code>${t}</code></summary>\n\n`;
    const files = byTest[t].sort((a, b) => a.file.localeCompare(b.file));
    for (const f of files) {
      md += `- **${f.file}**\n\n`;
      md +=
        `  <img src="${BASE}/diff/${f.flat}" alt="${f.file}" width="360">\n\n`;
    }
    md += `</details>\n\n`;
  }
}

md +=
  `<sub>Generated by <code>.github/workflows/visual-regression.yml</code> · `;
md +=
  `Run <a href="https://github.com/${REPO}/actions/runs/${RUN}">#${RUN}</a></sub>\n`;

fs.writeFileSync("comment.md", md);
process.stdout.write(md);
